// 2) CVE ID normalize — NVD recent + modified birlesimi, en guncel kayit kazanir
const map = {};
for (const item of $input.all()) {
  for (const v of (item.json.vulnerabilities || [])) {
    const c = v.cve || {};
    const id = (c.id || '').toUpperCase().trim();
    if (!/^CVE-\d{4}-\d{4,7}$/.test(id)) continue;
    const lastMod = c.lastModified || '';
    if (map[id] && map[id].lastModified >= lastMod) continue;

    const m = c.metrics || {};
    // CVSS fallback: v3.1 -> v3.0 -> v4.0 -> v2 (ilk dolu olani al)
    const pick = (arr) => (arr && arr[0]) ? arr[0] : null;
    const me31 = pick(m.cvssMetricV31), me30 = pick(m.cvssMetricV30),
          me40 = pick(m.cvssMetricV40), me2 = pick(m.cvssMetricV2);
    let cvssScore = null, cvssSeverity = null, cvssVector = null, cvssVersion = null;
    for (const cand of [
      me31 && { d: me31.cvssData, sev: me31.cvssData && me31.cvssData.baseSeverity, ver: '3.1' },
      me30 && { d: me30.cvssData, sev: me30.cvssData && me30.cvssData.baseSeverity, ver: '3.0' },
      me40 && { d: me40.cvssData, sev: me40.cvssData && me40.cvssData.baseSeverity, ver: '4.0' },
      me2  && { d: me2.cvssData,  sev: me2.baseSeverity, ver: '2.0' }
    ]) {
      if (cand && cand.d && cand.d.baseScore != null) {
        cvssScore = cand.d.baseScore;
        cvssSeverity = (cand.sev || cand.d.baseSeverity || '').toUpperCase() || null;
        cvssVector = cand.d.vectorString || null;
        cvssVersion = cand.ver;
        break;
      }
    }

    // CPE'den vendor:product ciftleri (KANIT) — eslestirme yalnizca bunlara gore
    const cpePairs = new Set();
    const walk = (nodes) => {
      for (const node of (nodes || [])) {
        for (const cm of (node.cpeMatch || [])) {
          // cpe:2.3:part:vendor:product:version:...
          const p = (cm.criteria || '').split(':');
          if (p.length > 4 && p[3] && p[4] && p[3] !== '*' && p[4] !== '*') {
            cpePairs.add((p[3] + ':' + p[4]).toLowerCase());
          }
        }
        if (node.children) walk(node.children);
      }
    };
    for (const conf of (c.configurations || [])) walk(conf.nodes || []);

    map[id] = {
      cveId: id,
      published: c.published || null,
      lastModified: lastMod,
      cvssScore: cvssScore,
      cvssSeverity: cvssSeverity,
      cvssVector: cvssVector,
      cvssVersion: cvssVersion,
      description: (((c.descriptions || []).find(x => x.lang === 'en') || {}).value || '').slice(0, 500),
      cwe: (c.weaknesses || []).flatMap(w => (w.description || []).map(d => d.value)).filter(x => x && x !== 'NVD-CWE-noinfo'),
      vendorRefs: (c.references || []).map(rf => rf.url).filter(Boolean).slice(0, 6),
      cpePairs: [...cpePairs],
      products: [...new Set([...cpePairs].map(x => x.split(':')[1]))]
    };
  }
}
return [{ json: { kind: 'nvd', count: Object.keys(map).length, data: map } }];

// 3) CISA KEV katalogunu cveId -> kayit haritasina cevir
const j = $input.first().json || {};
const map = {};
for (const v of (j.vulnerabilities || [])) {
  const id = (v.cveID || '').toUpperCase().trim();
  if (!id) continue;
  map[id] = {
    name: v.vulnerabilityName || '',
    dateAdded: v.dateAdded || null,
    dueDate: v.dueDate || null,
    ransomware: ((v.knownRansomwareCampaignUse || '') + '').toLowerCase() === 'known'
  };
}
return [{ json: { kind: 'kev', count: Object.keys(map).length, data: map } }];

// ====== RAPOR AYARLARI (AC/KAPA) ======
// Bu degerleri degistirerek rapor bolumlerini ac/kapat.
const SETTINGS = {
  includeDetectionQueries: true,  // CVE basina SPL + Sigma sorgusu uret ve "Tespit / Inceleme" bolumunu goster
  includeMitre: true              // CVE basina olasi MITRE ATT&CK teknigini goster
};
return [{ json: { kind: 'settings', data: SETTINGS } }];

// ====== DINAMIK FEED KAYDI ======
// Yeni feed eklemek icin bu listeye satir eklemeniz yeterli — baska dugum degisikligi gerekmez.
// kind === 'rss' olanlar otomatik cekilir. Diger kind'lar bilgi amacli durur:
//   api      -> ozel dugumlerle islenir (NVD API, EPSS, OSV, GitHub, VulnCheck)
//   json/csv -> KEV gibi ozel dugumlerle islenir
//   git/html -> n8n icinde guvenilir islenemez (cvelistV5, Rapid7, Qualys)
const FEEDS = [
  // --- exploit / PoC sinyali ---
  { id: 'exploit-db', name: 'Exploit-DB', kind: 'rss', category: 'public-exploit', url: 'https://www.exploit-db.com/rss.xml', enabled: true },
  { id: 'zdi-published-advisories', name: 'ZDI Published', kind: 'rss', category: 'zero-day-advisory', url: 'https://www.zerodayinitiative.com/rss/published/', enabled: true },
  { id: 'zdi-upcoming-advisories', name: 'ZDI Upcoming', kind: 'rss', category: 'zero-day-advisory', url: 'https://www.zerodayinitiative.com/rss/upcoming/', enabled: true },
  { id: 'packetstorm-exploits', name: 'Packet Storm Exploits', kind: 'rss', category: 'public-exploit', url: 'https://packetstormsecurity.com/files/tags/exploit/rss', enabled: true },

  // --- vendor PSIRT ---
  { id: 'microsoft-security-update-guide', name: 'Microsoft MSRC', kind: 'rss', category: 'vendor-advisory', url: 'https://api.msrc.microsoft.com/update-guide/rss', enabled: true },
  { id: 'cisco-security-advisories', name: 'Cisco PSIRT', kind: 'rss', category: 'vendor-advisory', url: 'https://sec.cloudapps.cisco.com/security/center/psirtrss10/CiscoSecurityAdvisory.xml', enabled: true },
  { id: 'fortinet-psirt-advisories', name: 'Fortinet PSIRT', kind: 'rss', category: 'vendor-advisory', url: 'https://filestore.fortinet.com/fortiguard/rss/ir.xml', enabled: true },
  { id: 'paloalto-security-advisories', name: 'Palo Alto PSIRT', kind: 'rss', category: 'vendor-advisory', url: 'https://security.paloaltonetworks.com/rss.xml', enabled: true },
  { id: 'oracle-security-alerts', name: 'Oracle CPU/Alerts', kind: 'rss', category: 'vendor-advisory', url: 'https://www.oracle.com/a/ocom/docs/corporate/rss-security-alerts.xml', enabled: true },
  { id: 'adobe-security-bulletins', name: 'Adobe Bulletins', kind: 'rss', category: 'vendor-advisory', url: 'https://helpx.adobe.com/security/security-bulletin.xml', enabled: true },
  { id: 'ubuntu-security-notices', name: 'Ubuntu USN', kind: 'rss', category: 'linux-security', url: 'https://ubuntu.com/security/notices/rss.xml', enabled: true },
  { id: 'jenkins-security-advisories', name: 'Jenkins Advisories', kind: 'rss', category: 'devsecops-security', url: 'https://www.jenkins.io/security/advisories/rss.xml', enabled: true },

  // --- scanner kapsami ---
  { id: 'tenable-security-advisories', name: 'Tenable Advisories', kind: 'rss', category: 'scanner-intelligence', url: 'https://www.tenable.com/security/tns/rss.xml', enabled: true },
  { id: 'tenable-newest-plugins', name: 'Tenable New Plugins', kind: 'rss', category: 'scanner-plugin', url: 'https://www.tenable.com/plugins/feeds?sort=newest', enabled: true },
  { id: 'tenable-updated-plugins', name: 'Tenable Updated Plugins', kind: 'rss', category: 'scanner-plugin', url: 'https://www.tenable.com/plugins/feeds?sort=updated', enabled: true },

  // --- ozel dugumlerle islenenler (bilgi amacli; rss olmadigi icin burada cekilmez) ---
  { id: 'nvd-api-2', name: 'NVD CVE API 2.0', kind: 'api', category: 'cve-database', url: 'https://services.nvd.nist.gov/rest/json/cves/2.0', enabled: true },
  { id: 'cisa-kev-catalog', name: 'CISA KEV Catalog', kind: 'json', category: 'known-exploited-vulnerability', url: 'https://www.cisa.gov/sites/default/files/feeds/known_exploited_vulnerabilities.json', enabled: true },
  { id: 'first-epss-api', name: 'FIRST EPSS API', kind: 'api', category: 'exploit-prediction', url: 'https://api.first.org/data/v1/epss', enabled: true },
  { id: 'osv-api', name: 'OSV.dev API', kind: 'api', category: 'package-security', url: 'https://api.osv.dev/v1/query', enabled: true },
  { id: 'github-global-security-advisories-api', name: 'GitHub Advisories API', kind: 'api', category: 'package-security', url: 'https://api.github.com/advisories', enabled: true },
  { id: 'vulncheck-exploit-intelligence', name: 'VulnCheck', kind: 'api', category: 'exploit-intelligence', url: 'https://api.vulncheck.com', enabled: false },
  // --- n8n icinde islenemeyenler ---
  { id: 'cve-org-cvelist-v5', name: 'CVE.org cvelistV5 (git)', kind: 'git', category: 'cve-database', url: 'https://github.com/CVEProject/cvelistV5', enabled: false },
  { id: 'rapid7-vulnerability-database', name: 'Rapid7 DB (html)', kind: 'html', category: 'scanner-intelligence', url: 'https://www.rapid7.com/db/', enabled: false },
  { id: 'qualys-security-alerts', name: 'Qualys Alerts (html)', kind: 'html', category: 'scanner-intelligence', url: 'https://www.qualys.com/research/security-alerts', enabled: false }
];
return FEEDS.filter(f => f.enabled && f.kind === 'rss').map(f => ({ json: f }));

// Kategoriye gore feed sec
const CATS = ["public-exploit","zero-day-advisory"];
const out = $input.all().filter(i => CATS.includes(i.json.category));
if (!out.length) out.push({ json: { url: 'about:blank', category: CATS[0], name: 'placeholder' } });
return out;

// 6) Exploit-DB + ZDI + PacketStorm -> PoC/exploit sinyal haritasi
const CVE_REGEX = /CVE-\d{4}-\d{4,7}/gi;
const map = {};
for (const item of $input.all()) {
  const j = item.json || {};
  const txt = [j.title, j.contentSnippet, j.content, j.summary].filter(Boolean).join(' ');
  let src = 'exploit-feed';
  try { src = new URL(j.link).hostname.replace(/^www\./, ''); } catch (e) {}
  for (const c of new Set((txt.match(CVE_REGEX) || []).map(x => x.toUpperCase()))) {
    (map[c] = map[c] || []).push({
      source: src,
      title: (j.title || '').slice(0, 150),
      link: j.link || '',
      date: j.isoDate || j.pubDate || ''
    });
  }
}
return [{ json: { kind: 'exploit', count: Object.keys(map).length, data: map } }];

// Kategoriye gore feed sec
const CATS = ["vendor-advisory","linux-security","devsecops-security"];
const out = $input.all().filter(i => CATS.includes(i.json.category));
if (!out.length) out.push({ json: { url: 'about:blank', category: CATS[0], name: 'placeholder' } });
return out;

// 8) Vendor PSIRT feed'leri -> patch/advisory sinyal haritasi
const CVE_REGEX = /CVE-\d{4}-\d{4,7}/gi;
const map = {};
for (const item of $input.all()) {
  const j = item.json || {};
  const txt = [j.title, j.contentSnippet, j.content, j.summary].filter(Boolean).join(' ');
  let vendor = 'vendor';
  try { vendor = new URL(j.link).hostname.replace(/^www\./, ''); } catch (e) {}
  for (const c of new Set((txt.match(CVE_REGEX) || []).map(x => x.toUpperCase()))) {
    (map[c] = map[c] || []).push({
      vendor,
      title: (j.title || '').slice(0, 150),
      link: j.link || '',
      date: j.isoDate || j.pubDate || ''
    });
  }
}
return [{ json: { kind: 'vendor', count: Object.keys(map).length, data: map } }];

// Kategoriye gore feed sec
const CATS = ["scanner-intelligence","scanner-plugin"];
const out = $input.all().filter(i => CATS.includes(i.json.category));
if (!out.length) out.push({ json: { url: 'about:blank', category: CATS[0], name: 'placeholder' } });
return out;

// 9) Tenable advisory + plugin feed'leri -> scanner kapsam haritasi
// (Rapid7/Qualys HTML sayfalari guvenilir parse edilemedigi icin kapsam disi — sticky nota bakin)
const CVE_REGEX = /CVE-\d{4}-\d{4,7}/gi;
const map = {};
for (const item of $input.all()) {
  const j = item.json || {};
  const txt = [j.title, j.contentSnippet, j.content, j.summary].filter(Boolean).join(' ');
  for (const c of new Set((txt.match(CVE_REGEX) || []).map(x => x.toUpperCase()))) {
    (map[c] = map[c] || []).push({
      source: 'tenable',
      title: (j.title || '').slice(0, 150),
      link: j.link || ''
    });
  }
}
return [{ json: { kind: 'scanner', count: Object.keys(map).length, data: map } }];

// Eslestirme artik 'Inventory Registry' dugumundeki envanterden gelir — burada config YOK.
const MAX_RECORDS = 200; // downstream zenginlestirme icin ust sinir

// Tum sinyal dallarini topla (Merge'den kind etiketiyle gelir)
const branches = {};
for (const it of $input.all()) branches[it.json.kind] = it.json.data || {};
const nvd = branches.nvd || {}, kev = branches.kev || {}, expl = branches.exploit || {},
      vend = branches.vendor || {}, scan = branches.scanner || {};
const inventory = Array.isArray(branches.inventory) ? branches.inventory : [];

// CVE evreni: NVD penceresi + exploit-sinyalli CVE'ler
const ids = new Set(Object.keys(nvd));
for (const c of Object.keys(expl)) ids.add(c);

const records = [];
for (const id of ids) {
  const n = nvd[id] || { cveId: id, cvssScore: null, cvssSeverity: null, cvssVector: null,
                         description: '', products: [], published: null, lastModified: null };
  const explHits = expl[id] || [], vendHits = vend[id] || [], scanHits = scan[id] || [];

  // ---- envanter eslestirme: YALNIZCA NVD CPE vendor:product kaniti ----
  const cvePairs = new Set((n.cpePairs || []).map(x => ('' + x).toLowerCase()));
  const matchedInventory = [];
  if (cvePairs.size) {
    for (const asset of inventory) {
      const assetCpes = (asset.cpe || []).map(x => ('' + x).toLowerCase());
      const hit = assetCpes.filter(cp => cvePairs.has(cp));
      if (hit.length) {
        matchedInventory.push({
          product: asset.product,
          owner: asset.owner || null,
          criticality: asset.criticality || null,
          dataClassification: asset.dataClassification || null,
          internetFacing: !!asset.internetFacing,
          matchedCpe: hit
        });
      }
    }
  }
  // CPE yoksa eslestirme YAPILMAZ (kanit yok -> halusinasyon yok)

  records.push({
    ...n,
    kev: kev[id] || null,
    knownExploited: !!kev[id],
    publicExploit: explHits.length > 0,
    exploitSignals: explHits.slice(0, 5),
    vendorPatch: vendHits.length > 0,
    vendorSignals: vendHits.slice(0, 5),
    scannerPlugin: scanHits.length > 0,
    scannerSignals: scanHits.slice(0, 3),
    matchedInventory,
    stackHits: matchedInventory.map(m => m.product),
    stackMatch: matchedInventory.length > 0,
    internetFacing: matchedInventory.some(m => m.internetFacing)
  });
}

// Ilginc olanlar: envanter eslesmesi VEYA KEV VEYA exploit sinyali VEYA CVSS>=9
let interesting = records.filter(r =>
  r.stackMatch || r.knownExploited || r.publicExploit || (r.cvssScore ?? 0) >= 9
);
interesting.sort((a, b) =>
  (b.stackMatch - a.stackMatch) || (b.knownExploited - a.knownExploited) ||
  (b.publicExploit - a.publicExploit) || ((b.cvssScore ?? 0) - (a.cvssScore ?? 0))
);
interesting = interesting.slice(0, MAX_RECORDS);

const stats = {
  nvdCves: Object.keys(nvd).length,
  kevTotal: Object.keys(kev).length,
  exploitSignaledCves: Object.keys(expl).length,
  vendorSignaledCves: Object.keys(vend).length,
  scannerSignaledCves: Object.keys(scan).length,
  inventoryAssets: inventory.length,
  candidateRecords: interesting.length,
  stackMatched: interesting.filter(r => r.stackMatch).length,
  runAt: new Date().toISOString()
};

return [{ json: { stats, records: interesting } }];

// 4) EPSS API icin CVE listesini 50'lik gruplara bol
const records = $input.first().json.records || [];
const ids = records.map(r => r.cveId);
if (!ids.length) return [{ json: { cveBatch: null, _empty: true } }];
const batches = [];
for (let i = 0; i < ids.length; i += 50) batches.push(ids.slice(i, i + 50).join(','));
return batches.map(b => ({ json: { cveBatch: b } }));

// EPSS yanitlarini topla ve kayitlara isle
const epssMap = {};
for (const item of $input.all()) {
  for (const row of (item.json.data || [])) {
    epssMap[(row.cve || '').toUpperCase()] = {
      epss: parseFloat(row.epss),
      percentile: parseFloat(row.percentile)
    };
  }
}
const payload = $('Correlate + Stack Filter').first().json;
for (const r of payload.records) {
  const e = epssMap[r.cveId];
  r.epss = e ? e.epss : null;
  r.epssPercentile = e ? e.percentile : null;
}
payload.stats.epssScored = Object.keys(epssMap).length;
return [{ json: payload }];

// 5+7) GitHub/OSV/VulnCheck per-CVE zenginlestirme — sadece en kritik adaylar
const MAX_OSS_LOOKUPS = 15; // GitHub anonim limiti 60/saat; 6h cadence ile guvenli
const records = $('Merge EPSS Scores').first().json.records || [];
const candidates = records
  .filter(r => r.stackMatch || r.knownExploited || (r.epss ?? 0) >= 0.5)
  .slice(0, MAX_OSS_LOOKUPS);
if (!candidates.length) return [{ json: { cveId: null, _noCves: true } }];
return candidates.map(r => ({ json: { cveId: r.cveId } }));

// GitHub Advisory + OSV + GitHub PoC repo aramasini tek kayda indir
const cveId = $('Loop OSS Enrichment').first().json.cveId;
const out = { cveId, ghAdvisories: 0, ghEcosystems: [], ghSeverity: null,
              osvFound: false, osvAffected: [], pocCount: 0, pocRepos: [], pocTopStars: 0 };

// GitHub Advisory (dizi yaniti item'lara bolunur -> dugum referansiyla oku)
const eco = new Set();
try {
  for (const item of $('GitHub Advisories Lookup').all()) {
    const a = item.json || {};
    if (!a.ghsa_id && !a.cve_id) continue;
    out.ghAdvisories++;
    if (a.severity && !out.ghSeverity) out.ghSeverity = a.severity;
    for (const v of (a.vulnerabilities || [])) {
      const e = v.package && v.package.ecosystem;
      if (e) eco.add(e);
    }
  }
} catch (e) {}
out.ghEcosystems = [...eco];

// OSV
try {
  const osv = $('OSV Lookup').first().json;
  if (osv && osv.id) {
    out.osvFound = true;
    const aff = new Set();
    for (const a of (osv.affected || [])) {
      const p = a.package || {};
      if (p.name) aff.add((p.ecosystem ? p.ecosystem + '/' : '') + p.name);
    }
    out.osvAffected = [...aff].slice(0, 10);
  }
} catch (e) {}

// GitHub PoC repo aramasi ($input = search/repositories yaniti)
try {
  const gh = $input.first().json || {};
  const items = gh.items || [];
  out.pocCount = gh.total_count ?? items.length;
  out.pocRepos = items.slice(0, 3).map(r => ({ name: r.full_name, url: r.html_url, stars: r.stargazers_count }));
  out.pocTopStars = items.length ? Math.max(...items.map(r => r.stargazers_count || 0)) : 0;
} catch (e) {}

return [{ json: out }];

// 10) Onceliklendirme matrisi — Critical/High/Medium/Low
const payload = $('Merge EPSS Scores').first().json;
const records = payload.records || [];

// OSS sonuclarini isle
const ossMap = {};
for (const o of ($input.first().json.ossResults || [])) {
  if (o && o.cveId) ossMap[o.cveId] = o;
}
for (const r of records) {
  const o = ossMap[r.cveId];
  r.packageImpact = o ? { ghAdvisories: o.ghAdvisories, ecosystems: o.ghEcosystems, osvAffected: o.osvAffected } : null;
  if (o) {
    r.pocRepos = o.pocRepos || [];
    r.pocCount = o.pocCount || 0;
    r.pocTopStars = o.pocTopStars || 0;
    if (r.pocCount > 0) r.publicExploit = true; // GitHub'da PoC repo varligi da exploit sinyalidir
  }
}

function score(r) {
  const reasons = [];
  const epss = r.epss ?? 0, cvss = r.cvssScore ?? 0;

  // ---- CRITICAL: stack eslesmesi + agir istismar sinyali ----
  if (r.stackMatch) {
    if (r.knownExploited) reasons.push('CISA KEV (aktif istismar)');
    if (r.publicExploit && epss >= 0.70) reasons.push('Public exploit + EPSS>=0.70');
    if (cvss >= 9.0 && r.internetFacing) reasons.push('CVSS>=9.0 + internet-facing urun');
    if (reasons.length) return ['CRITICAL', reasons];

    // ---- HIGH ----
    if (epss >= 0.50) reasons.push('EPSS>=0.50');
    if (r.publicExploit && !r.knownExploited) reasons.push('PoC var, aktif istismar dogrulanmadi');
    if (r.vendorPatch) reasons.push('Vendor patch/advisory yayinlandi');
    if (r.scannerPlugin) reasons.push('Scanner plugin mevcut');
    if (reasons.length) return ['HIGH', reasons];

    // ---- MEDIUM: kurumda var ama sinyal zayif ----
    return ['MEDIUM', [r.internetFacing ? 'Stack eslesmesi, dusuk istismar sinyali' : 'Stack eslesmesi var, internet-facing degil']];
  }

  // Stack eslesmesi yok:
  if (cvss >= 7.0 && !r.publicExploit && !r.knownExploited) return ['MEDIUM', ['CVSS yuksek, exploit/KEV yok']];
  if (r.knownExploited || r.publicExploit) return ['MEDIUM', ['Istismar sinyali var, stack eslesmesi yok']];
  if (r.vendorPatch || r.scannerPlugin) return ['LOW', ['Yalnizca advisory/plugin sinyali']];
  return ['LOW', ['Dusuk sinyal']];
}

const buckets = { CRITICAL: [], HIGH: [], MEDIUM: [], LOW: [] };
for (const r of records) {
  const [p, reasons] = score(r);
  r.priority = p; r.priorityReasons = reasons;
  buckets[p].push(r);
}
const slim = r => ({
  cveId: r.cveId, cvssScore: r.cvssScore, cvssSeverity: r.cvssSeverity, cvssVector: r.cvssVector, cvssVersion: r.cvssVersion || null, cwe: r.cwe || [], published: r.published, lastModified: r.lastModified,
  vendorRefs: r.vendorRefs || [],
  previouslyNotified: r.previouslyNotified || false,
  firstNotifiedAt: r.firstNotifiedAt || null,
  epss: r.epss, knownExploited: r.knownExploited, ransomware: r.kev ? r.kev.ransomware : false,
  publicExploit: r.publicExploit, vendorPatch: r.vendorPatch, scannerPlugin: r.scannerPlugin,
  stackHits: r.stackHits, internetFacing: r.internetFacing, priority: r.priority,
  matchedInventory: r.matchedInventory || [],
  businessCriticality: (r.matchedInventory || []).reduce((acc, m) => {
    const rank = { critical: 4, high: 3, medium: 2, low: 1 };
    return (rank[(m.criticality||'').toLowerCase()] || 0) > (rank[(acc||'').toLowerCase()] || 0) ? m.criticality : acc;
  }, null),
  dataClassifications: [...new Set((r.matchedInventory || []).map(m => m.dataClassification).filter(Boolean))],
  cpeProducts: (r.products || []).slice(0, 8),
  pocCount: r.pocCount || 0, pocTopStars: r.pocTopStars || 0, pocRepos: (r.pocRepos || []).slice(0, 2),
  priorityReasons: r.priorityReasons,
  packageImpact: r.packageImpact,
  description: (r.description || '').slice(0, 200),
  refs: [...(r.exploitSignals || []), ...(r.vendorSignals || [])].slice(0, 3).map(s => s.link)
});

const stats = {
  ...payload.stats,
  criticalCount: buckets.CRITICAL.length,
  highCount: buckets.HIGH.length,
  mediumCount: buckets.MEDIUM.length,
  lowCount: buckets.LOW.length
};

return [{ json: {
  stats,
  critical: buckets.CRITICAL.slice(0, 15).map(slim),
  high: buckets.HIGH.slice(0, 20).map(slim),
  mediumSample: buckets.MEDIUM.slice(0, 10).map(slim),
  inventoryMatched: records.filter(r => r.stackMatch).slice(0, 25).map(slim)
}}];

// Mod tespiti + moda gore filtreleme + 4 saatlik pencere (yalniz saatlik)
const payload = $('Priority Scoring').first().json;
let matched = payload.inventoryMatched || [];
const order = { CRITICAL: 0, HIGH: 1, MEDIUM: 2, LOW: 3 };

let settings = { includeDetectionQueries: true, includeMitre: true };
try { settings = { ...settings, ...($('Report Settings').first().json.data || {}) }; } catch (e) {}

// Mod: hourly | daily | api | manual (her execution'da yalniz biri tetiklenir)
let mode = 'manual';
try { if ($('Schedule Trigger (Every 6h)').isExecuted) mode = 'hourly'; } catch (e) {}
try { if ($('Schedule Daily (24h)').isExecuted) mode = 'daily'; } catch (e) {}
try { if ($('Report API Trigger').isExecuted) mode = 'api'; } catch (e) {}

const WINDOW_MS = 4 * 60 * 60 * 1000;
const now = Date.now();
const sd = $getWorkflowStaticData('global');
sd.notifyLog = sd.notifyLog || {};

if (mode === 'hourly') {
  // Saatlik: SADECE internet-facing eslesmeler
  matched = matched.filter(r => (r.matchedInventory || []).some(m => m.internetFacing));
  // 4 saatlik pencere + 'daha once bildirildi' etiketi (purge 24s)
  const PURGE_MS = 24 * 60 * 60 * 1000;
  for (const k of Object.keys(sd.notifyLog)) { if (now - sd.notifyLog[k] > PURGE_MS) delete sd.notifyLog[k]; }
  const kept = [];
  for (const r of matched) {
    const first = sd.notifyLog[r.cveId];
    if (first == null) { sd.notifyLog[r.cveId] = now; kept.push({ ...r, previouslyNotified: false }); }
    else if (now - first <= WINDOW_MS) { kept.push({ ...r, previouslyNotified: true, firstNotifiedAt: new Date(first).toISOString() }); }
  }
  matched = kept;
} else {
  // daily / api / manual: TUM eslesmeler, pencere yok, etiket yok
  matched = matched.map(r => ({ ...r, previouslyNotified: false }));
}

matched.sort((a, b) => (order[a.priority] ?? 9) - (order[b.priority] ?? 9) || (b.cvssScore ?? 0) - (a.cvssScore ?? 0));
const capped = matched.slice(0, 50);
if (!capped.length) return [{ json: { _empty: true, _settings: settings, _mode: mode } }];
return capped.map(r => ({ json: { ...r, _settings: settings, _mode: mode } }));

parameters.text:
=Sen kidemli bir zafiyet analisti, sizma testi uzmani ve detection engineer'sin. Sana TEK bir CVE'nin zenginlestirilmis verisi veriliyor. Gorevin SADECE asagidaki semaya birebir uyan gecerli bir JSON dondurmek. JSON disinda HICBIR metin, aciklama, markdown veya kod citi yazma.

CVE verisi:
- ID: {{ $json.cveId }}
- CVSS: {{ $json.cvssScore }} ({{ $json.cvssSeverity }}) | vektor: {{ $json.cvssVector }}
- CWE: {{ ($json.cwe || []).join(', ') }}
- EPSS: {{ $json.epss }}
- CISA KEV: {{ $json.knownExploited }} (ransomware: {{ $json.ransomware }})
- Public PoC: {{ $json.publicExploit }} | GitHub repo: {{ $json.pocCount }}
- Etkilenen envanter: {{ ($json.matchedInventory || []).map(m => m.product + (m.internetFacing ? ' [internet-facing]' : '')).join('; ') }}
- Aciklama: {{ $json.description }}

Istenen JSON (anahtarlar birebir, hepsi Turkce):
{"ozet": "1-2 cumle: zafiyet nedir ve neden onemli", "saldiriVektoru": "Saldirinin nasil gerceklestigi: erisim yolu (ag/yerel), kimlik dogrulama gereksinimi, kullanici etkilesimi; CVSS vektorunu sade dille acikla.", "somuru": "Sizma testi bakisiyla pratik somuru: on kosullar, adimlar, olasi etki. Veri sinirliysa belirt, uydurma.", "iocTespit": "Detection engineering: hangi log kaynagi (or. Apache/Nginx access log, Sysmon, Zeek, WAF), aranacak IOC/gosterge/pattern.", "mitigasyon": "Patch + gecici workaround + telafi edici kontrol (compensating control). Spesifik ol, surum numarasi uydurma.", "mitre": "Olasi MITRE ATT&CK teknigi: Teknik adi ve ID (or. 'Exploit Public-Facing Application T1190'). Birden fazla olabilir. Emin degilsen en olasi olani ver ve 'olasi' de.", "splAciklama": "1-2 cumle: SPL sorgusu neyi tespit ediyor, hangi log kaynagini/alanlari kullaniyor ve mantigi nedir.", "spl": "Kapsamli, calistirilabilir bir Splunk SPL sorgusu. Gercekci index/sourcetype/alan adlari, zaman penceresi, gerektiginde stats/eval/where ile esik veya korelasyon iceren cok satirli bir sorgu yaz. SOC ortamina gore uyarlanmasi gerektigini varsay.", "sigmaAciklama": "1-2 cumle: Sigma kuralinin amaci, hedef log kaynagi ve tespit mantigi.", "sigma": "Tam ve gecerli bir Sigma kurali (YAML): title, status, description, logsource (category/product/service), detection (selection ve gerekirse filter/condition), falsepositives, level alanlarini icersin. Genis kapsamli yaz."}

NOT: mitre, spl ve sigma alanlari yalnizca ilgili ayar acikken kullanilir; her durumda uretmen sorun degil.

Kurallar: Yalnizca verilen veriyi kullan. Surum/patch numarasi uydurma. Cikti SADECE JSON olsun.
ZORUNLU ALAN AYRIMI: "ozet", "saldiriVektoru", "somuru", "iocTespit", "mitigasyon" alanlari DUZ TURKCE CUMLE olmali; bunlarin icine ASLA SPL/Splunk sorgusu, Sigma/YAML kurali veya kod yazma. SPL yalnizca "spl" alaninda, Sigma yalnizca "sigma" alaninda yer alir. "ozet" 1-2 cumlelik insan diliyle aciklamadir; "index=", "sourcetype=", "| stats", "title:", "logsource:" gibi ifadeler ozet/somuru/iocTespit icinde KESINLIKLE bulunmamalidir.

parameters.jsCode:
// LLM JSON ciktisini ayristir, kayda ekle, donguye geri besle
const rec = $('Loop Analysis').first().json;
if (rec._empty) return [{ json: { _empty: true } }];

let raw = ($json.text || $json.output || '').toString().trim();
raw = raw.replace(/^[\s\S]*?\u0060\u0060\u0060(?:json)?/i, '').replace(/\u0060\u0060\u0060[\s\S]*$/i, '').trim();

let a = {};
try { a = JSON.parse(raw); }
catch (e) {
  const m = raw.match(/\{[\s\S]*\}/);
  try { a = m ? JSON.parse(m[0]) : {}; } catch (_) { a = {}; }
}

// Sorgu/kural sozdizimi tespiti: bir alan SPL/Sigma/kod icerigine mi kaymis?
const looksLikeQuery = (s) => {
  if (!s) return false;
  s = ('' + s).trim();
  return /^(spl|sigma|yaml|json)\b/i.test(s) ||                       // 'splunk index=...', 'yaml title:...'
    /\bindex\s*=|\bsourcetype\s*=|EventCode\s*=|\|\s*stats\b|\|\s*where\b|\|\s*search\b/i.test(s) || // SPL
    /^\s*title:\s|logsource:|detection:\s|condition:\s/im.test(s);    // Sigma/YAML
};
let spl = a.spl || a.splunk || '';
let sigma = a.sigma || '';

// ozet hesapla; sorgu icerigi sizmissa temizle ve mumkunse dogru alana tasi
let ozet = a.ozet || a.summary || '';
if (looksLikeQuery(ozet)) {
  const t = ('' + ozet).trim();
  if (/^\s*title:|logsource:|detection:/im.test(t) || /^(yaml|sigma)\b/i.test(t)) { if (!sigma) sigma = t.replace(/^(yaml|sigma)\s*/i, ''); }
  else { if (!spl) spl = t.replace(/^splunk\s*/i, ''); }
  ozet = '';  // bozuk ozeti dusur
}
if (!ozet) {
  // guvenli yedek: aciklamadan tek cumle (sorgu degilse), yoksa CVE kimligi
  const descSentence = ('' + (rec.description || '')).split(/(?<=[.!?])\s/)[0];
  ozet = (descSentence && !looksLikeQuery(descSentence)) ? descSentence.slice(0, 200) : (rec.cveId + ' zafiyeti icin ozet uretilemedi.');
}

// diger prose alanlarda da sorgu sizmasini temizle
const clean = (v, fb) => (v && !looksLikeQuery(v)) ? v : fb;

const analysis = {
  ozet: ozet,
  saldiriVektoru: clean(a.saldiriVektoru || a.attackVector, '-'),
  somuru: clean(a.somuru || a.exploit || a.exploitScenario, 'Teknik somuru verisi sinirli.'),
  iocTespit: clean(a.iocTespit || a.tespit || a.detection, 'Tespit onerisi uretilemedi.'),
  mitigasyon: clean(a.mitigasyon || a.mitigation, '-'),
  mitre: a.mitre || a.mitreAttack || '-',
  spl: spl,
  splAciklama: clean(a.splAciklama || a.splExplanation, ''),
  sigma: sigma,
  sigmaAciklama: clean(a.sigmaAciklama || a.sigmaExplanation, '')
};
return [{ json: { ...rec, analysis, previouslyNotified: rec.previouslyNotified || false, firstNotifiedAt: rec.firstNotifiedAt || null } }];

// Yonetici ozeti LLM'i icin kompakt girdi hazirla
const reports = ($('Aggregate Analyses').first().json.reports || []).filter(r => r && !r._empty && r.cveId);
const ps = $('Priority Scoring').first().json;
const stats = ps.stats || {};
const matchedN = (ps.inventoryMatched || []).length;
const M = reports.length;
const ifc = reports.filter(r => (r.matchedInventory || []).some(m => m.internetFacing)).length;
const kevc = reports.filter(r => r.knownExploited).length;
const order = { CRITICAL: 0, HIGH: 1, MEDIUM: 2, LOW: 3 };
// Oncelik dagilimi: RAPORLANAN (eslesen) CVE'ler uzerinden say — global tarama degil
const crit = reports.filter(r => r.priority === 'CRITICAL').length;
const high = reports.filter(r => r.priority === 'HIGH').length;
const med  = reports.filter(r => r.priority === 'MEDIUM').length;
const low  = reports.filter(r => r.priority === 'LOW').length;
const top = reports.slice().sort((a, b) => (order[a.priority] ?? 9) - (order[b.priority] ?? 9) || (b.cvssScore ?? 0) - (a.cvssScore ?? 0))
  .slice(0, 5)
  .map(r => r.cveId + ' (CVSS ' + (r.cvssScore ?? '?') + ', ' + (r.matchedInventory || []).map(m => m.product).join('/') + (r.knownExploited ? ', KEV' : '') + ')')
  .join('; ');
return [{ json: { summary: {
  nvdCves: stats.nvdCves ?? '?', matchedN, M,
  criticalCount: crit, highCount: high, mediumCount: med, lowCount: low,
  internetFacingCount: ifc, kevCount: kevc, topList: top || '(yok)'
}}}];

parameters.text:
=Sen kidemli bir zafiyet istihbarat yoneticisisin (CISO ofisi). Asagidaki ozet veriden 5-6 cumlelik bir YONETICI OZETI yaz. Teknik jargon minimum; is etkisi, maruziyet (internet-facing), aktif istismar/KEV ve onceliklendirme vurgulansin. Somut sayilar kullan. SADECE ozet metni dondur; baslik, madde, markdown veya talimat tekrari YOK.

Veri (TUM sayilar envanterle eslesen/raporlanan kume icindir, genel tarama degil):
- Genel tarama: {{ $json.summary.nvdCves }} CVE tarandi (baglam icin; bunlarin yalnizca eslesenleri raporlanir)
- Envanterle eslesen ve raporlanan: {{ $json.summary.M }} CVE
- Raporlanan {{ $json.summary.M }} CVE'nin oncelik dagilimi: {{ $json.summary.criticalCount }} kritik / {{ $json.summary.highCount }} yuksek / {{ $json.summary.mediumCount }} orta / {{ $json.summary.lowCount }} dusuk
- Bunlardan internet-facing olan: {{ $json.summary.internetFacingCount }}
- Bunlardan aktif istismar edilen (KEV): {{ $json.summary.kevCount }}
- En kritik bulgular: {{ $json.summary.topList }}

ONEMLI: Oncelik sayilari (kritik/yuksek/orta) RAPORLANAN {{ $json.summary.M }} CVE icindir. "X zafiyet eslesti, bunlarin Y'si yuksek" derken Y, M'yi asamaz; tutarli ol. Genel tarama sayisini (toplam taranan) yalnizca baglam olarak, ayri bir cumlede belirt.

parameters.jsCode:
// Tek konsolide, e-posta-guvenli HTML rapor (inline CSS, tablo tabanli)
const reports = ($('Aggregate Analyses').first().json.reports || []).filter(r => r && !r._empty && r.cveId);
const ps = $('Priority Scoring').first().json;
const stats = ps.stats || {};
const matchedN = (ps.inventoryMatched || []).length;
let RS = { includeDetectionQueries: true, includeMitre: true };
try { RS = { ...RS, ...((reports[0] && reports[0]._settings) || {}) }; } catch (e) {}
let MODE = 'manual';
try { MODE = $('Prepare Analysis Queue').first().json._mode || ((reports[0] && reports[0]._mode) || 'manual'); } catch (e) {}
const ifCount = reports.filter(r => (r.matchedInventory || []).some(m => m.internetFacing)).length;
const shouldNotify = (MODE === 'hourly') ? (ifCount > 0) : (MODE === 'api' ? false : true);
const M = reports.length;

const sd = $getWorkflowStaticData('global');
const prev = sd.lastReport || null;
const delta = prev && typeof prev.reportsGenerated === 'number' ? (M - prev.reportsGenerated) : null;
const deltaTxt = delta == null ? '' : ((delta >= 0 ? '+' + delta : '' + delta) + ' (önceki: ' + prev.reportsGenerated + ')');

const esc = s => String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const order = { CRITICAL: 0, HIGH: 1, MEDIUM: 2, LOW: 3 };
reports.sort((a, b) => (order[a.priority] ?? 9) - (order[b.priority] ?? 9) || (b.cvssScore ?? 0) - (a.cvssScore ?? 0));
const crit = reports.filter(r => r.priority === 'CRITICAL');
const internetFacing = reports.filter(r => (r.matchedInventory || []).some(m => m.internetFacing));

// ---- palet (ornek sablondan) ----
const C = { navy: '#001C30', navyMed: '#176B87', orange: '#FF6B00', orangeLt: '#FFD3B0', bg: '#F8F9FA', border: '#DEE2E6', white: '#FFFFFF' };
const sev = { CRITICAL: '#FF6B6B', HIGH: '#FF8B94', MEDIUM: '#FFD3B0', LOW: '#A8E6CF' };
const topPriority = crit.length ? 'CRITICAL' : (reports.some(r => r.priority === 'HIGH') ? 'HIGH' : (reports.length ? 'MEDIUM' : 'LOW'));

const invStr = r => (r.matchedInventory || [])
  .map(m => esc(m.product) + (m.owner ? ' (' + esc(m.owner) + ')' : '') + (m.internetFacing ? ' <b style="color:' + C.orange + '">[internet-facing]</b>' : ''))
  .join(', ') || '-';

// ---- kart sarmalayici ----
const card = (title, inner) =>
  '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:' + C.white + ';border-radius:12px;border-top:4px solid ' + C.orange + ';box-shadow:0 4px 6px rgba(0,0,0,0.05);margin:0 0 22px 0">' +
  '<tr><td style="padding:22px 24px">' +
  (title ? '<h3 style="margin:0 0 14px 0;color:' + C.navy + ';font-size:17px">' + title + '</h3>' : '') + inner +
  '</td></tr></table>';

// ---- metrik satiri ----
const metric = (label, value, hl) =>
  '<tr><td style="padding:12px 0;border-bottom:1px solid ' + C.border + ';color:' + C.navy + '">' + label + '</td>' +
  '<td align="right" style="padding:12px 0;border-bottom:1px solid ' + C.border + ';font-weight:bold;color:' + (hl ? C.orange : C.navyMed) + '">' + value + '</td></tr>';

const metricsCard = card('Temel Metrikler',
  '<table role="presentation" width="100%" cellpadding="0" cellspacing="0">' +
  metric('Taranan CVE (son 30s)', (stats.nvdCves ?? '?')) +
  metric('CISA KEV katalog', (stats.kevTotal ?? '?')) +
  metric('Envanter eşleşmesi', matchedN) +
  metric('Detaylı rapor üretilen', M, matchedN !== M) +
  metric('İnternete açık etkilenen', internetFacing.length, internetFacing.length > 0) +
  '</table>');

// ---- kritiklik skalasi ----
const segFlex = { LOW: [2,1,1,1], MEDIUM: [1,2,1,1], HIGH: [1,1,2,1], CRITICAL: [1,1,1,3] }[topPriority];
const scale =
  '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="margin:18px 0"><tr>' +
  ['#A8E6CF', '#FFD3B0', '#FF8B94', '#FF6B6B'].map((c, idx) =>
    '<td height="12" style="background:' + c + ';' +
    (idx === 0 ? 'border-radius:6px 0 0 6px;' : idx === 3 ? 'border-radius:0 6px 6px 0;' : '') +
    'width:' + (segFlex[idx] * 20) + '%' +
    (['LOW','MEDIUM','HIGH','CRITICAL'][idx] === topPriority ? ';border:2px solid ' + C.navy : '') + '"></td>').join('') +
  '</tr></table>';
const critCard = card('Kritiklik Durumu',
  '<p style="margin:0 0 6px 0;color:' + C.navyMed + '">Önceliklendirme sonucu organizasyonel etki:</p>' + scale +
  '<p style="margin:6px 0"><strong>Seviye: <span style="color:' + C.orange + '">' + topPriority + '</span></strong></p>' +
  '<p style="margin:6px 0;color:' + C.navy + '">' + (crit.length ? (crit.length + ' kritik bulgu envanterinizi etkiliyor; internet-facing varlıklara öncelik verin.') : 'Kritik öncelikli bulgu yok; yüksek/orta öncelikliler izlemede.') + '</p>');

// ---- yonetici ozeti (LLM) ----
let execSummary = '';
try { execSummary = ($('Exec Summary LLM').first().json.text || '').toString().trim(); } catch (e) {}
execSummary = execSummary.replace(/[*_\u0060#]/g, '');
if (!execSummary) {
  execSummary = 'Son 30 saatte ' + (stats.nvdCves ?? '?') + ' CVE tarandi; ' + matchedN + ' tanesi envanterle eslesti, ' + M +
    ' tanesi icin detayli analiz uretildi. ' + (stats.criticalCount ?? 0) + ' kritik oncelikli bulgu mevcut. ' +
    'Internet-facing varliklara ve aktif istismar edilen zafiyetlere oncelik verilmelidir.';
}

// ---- bulgular tablosu ----
const sevColor = { CRITICAL: C.orange, HIGH: '#e67e22', MEDIUM: C.navyMed, LOW: '#7f8c8d' };
const th = (t, r) => '<th align="left" style="padding:11px 10px;background:' + C.navyMed + ';color:#fff;font-size:13px' + (r === 'l' ? ';border-radius:6px 0 0 0' : r === 'r' ? ';border-radius:0 6px 0 0' : '') + '">' + t + '</th>';
const findingRows = reports.slice(0, 50).map(r => {
  const env = (r.matchedInventory || []).some(m => m.internetFacing) ? 'İnternete Açık' : 'İç Ortam';
  const prod = [...new Set((r.matchedInventory || []).map(m => m.product))].map(esc).join(', ') || '-';
  const bc = esc(r.businessCriticality || '-');
  return '<tr>' +
    '<td style="padding:9px 10px;border-bottom:1px solid #eee;font-weight:bold">' + esc(r.cveId) + (r.previouslyNotified ? ' <span style="color:#999;font-weight:normal;font-size:11px">↺</span>' : '') + '</td>' +
    '<td style="padding:9px 10px;border-bottom:1px solid #eee">' + (r.cvssScore != null ? r.cvssScore : '—') + '</td>' +
    '<td style="padding:9px 10px;border-bottom:1px solid #eee">' + (r.epss != null ? (r.epss * 100).toFixed(1) + '%' : '-') + '</td>' +
    '<td style="padding:9px 10px;border-bottom:1px solid #eee">' + (env === 'İnternete Açık' ? '<b style="color:' + C.orange + '">' + env + '</b>' : env) + '</td>' +
    '<td style="padding:9px 10px;border-bottom:1px solid #eee">' + prod + '</td>' +
    '<td style="padding:9px 10px;border-bottom:1px solid #eee;color:' + (sevColor[r.priority] || C.navyMed) + ';font-weight:bold">' + esc(r.priority) + '</td>' +
    '</tr>';
}).join('');
const findingsTable =
  '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;font-size:13px;margin-top:6px">' +
  '<tr>' + th('CVE', 'l') + th('CVSS') + th('EPSS') + th('Ortam') + th('Ürün') + th('Kritiklik', 'r') + '</tr>' +
  (findingRows || '<tr><td colspan="6" style="padding:12px">Envanterle eşleşen bulgu yok.</td></tr>') +
  '</table>';

const findingsCard = card('Yönetici Özeti ve Bulgular',
  '<p style="margin:0 0 6px 0;line-height:1.6;color:' + C.navy + '">' + esc(execSummary) + '</p>' +
  (reports.some(r => r.previouslyNotified) ? '<p style="margin:8px 0 0 0;font-size:12px;color:#888">↺ işaretli bulgular son 4 saat içinde daha önce bildirildi. 4 saatten eski bildirimler rapora dahil edilmez.</p>' : '') +
  '<p style="margin:10px 0 4px 0;color:' + C.navyMed + ';font-size:13px">Sayı karşılaştırması: Flow 1 eşleşen <b>' + matchedN + '</b> · detaylı rapor <b>' + M + '</b>' +
  (deltaTxt ? ' · ' + deltaTxt : '') +
  (matchedN !== M ? ' · <span style="color:#c0392b">' + (matchedN - M) + ' CVE rapora girmedi</span>' : '') + '</p>' +
  findingsTable);

// ---- Tespit / Inceleme bolumu (SPL + Sigma), ac/kapa ayariyla ----
const codeBox = (label, content) =>
  '<div style="margin:6px 0"><div style="font-size:12px;font-weight:bold;color:' + C.navyMed + '">' + label + '</div>' +
  '<pre style="margin:3px 0;padding:10px 12px;background:#0d1b2a;color:#e0e6ed;border-radius:6px;font-family:Consolas,Monaco,monospace;font-size:12px;white-space:pre-wrap;word-break:break-word;overflow-x:auto">' + content + '</pre></div>';
const detectionBlock = r => {
  const a = r.analysis || {};
  const spl = (a.spl || '').toString().trim();
  const sigma = (a.sigma || '').toString().trim();
  if (!spl && !sigma) return '';
  const splExp = (a.splAciklama || '').toString().trim();
  const sigExp = (a.sigmaAciklama || '').toString().trim();
  const note = (t) => t ? '<p style="margin:4px 0;font-size:12px;color:#555;line-height:1.5">' + esc(t) + '</p>' : '';
  return '<div style="margin:10px 0;padding:12px 14px;background:#f4f7fa;border:1px solid ' + C.border + ';border-radius:8px">' +
    '<div style="font-weight:bold;color:' + C.navy + ';margin-bottom:4px">🔎 Tespit / İnceleme</div>' +
    '<p style="margin:2px 0 8px 0;font-size:11px;color:#888">Aşağıdaki sorgular otomatik üretildi; SOC ortamınızdaki index/sourcetype/alan adlarına göre uyarlayın.</p>' +
    (spl ? note(splExp) + codeBox('Splunk SPL', esc(spl)) : '') +
    (sigma ? note(sigExp) + codeBox('Sigma', esc(sigma)) : '') +
    '</div>';
};

// ---- Zafiyet referans linkleri ----
const refsBlock = r => {
  const cid = encodeURIComponent(r.cveId);
  const links = [
    { label: 'NVD', url: 'https://nvd.nist.gov/vuln/detail/' + cid },
    { label: 'MITRE CVE.org', url: 'https://www.cve.org/CVERecord?id=' + cid }
  ];
  for (const u of (r.vendorRefs || []).slice(0, 5)) {
    let host = u;
    try { host = new URL(u).hostname.replace(/^www\./, ''); } catch (e) {}
    links.push({ label: host, url: u });
  }
  return '<p style="margin:6px 0;font-size:12px;color:#555"><b style="color:' + C.navyMed + '">Referanslar:</b> ' +
    links.map(l => '<a href="' + esc(l.url) + '" style="color:' + C.navyMed + '">' + esc(l.label) + '</a>').join(' · ') + '</p>';
};

// ---- CVE basina detayli teknik bolum ----
const detailBlock = r => {
  const a = r.analysis || {};
  const mi = r.matchedInventory || [];
  // Yayin tarihi 30 gunden eski ama son 30 saatte guncellenmis -> 'guncellendi (eski CVE)'
  let updatedOld = false, pubStr = '';
  try {
    if (r.published) {
      pubStr = ('' + r.published).slice(0, 10);
      const pubMs = Date.parse(r.published);
      if (!isNaN(pubMs) && (Date.now() - pubMs) > 30 * 24 * 3600 * 1000) updatedOld = true;
    }
  } catch (e) {}
  const products = mi.map(m => m.product);
  const assetsStr = mi.map(m => esc(m.product) + (m.owner ? ' (' + esc(m.owner) + ')' : '')).join(', ') || '-';
  const watchlist = [...new Set(products)].map(esc).join(', ') || '-';
  const ifx = mi.some(m => m.internetFacing);
  const dataClass = (r.dataClassifications || []).join(', ') || '-';
  const cpeStr = (r.cpeProducts || []).length ? (r.cpeProducts || []).map(esc).join(', ') : '-';
  const cpeOk = (r.cpeProducts || []).length > 0;
  const hasPocLinks = (r.pocRepos || []).length > 0;
  const hasPocCount = (r.pocCount || 0) > 0;
  const istismar = r.knownExploited
    ? ('Aktif istismar (CISA KEV)' + (r.ransomware ? ' · ransomware' : ''))
    : (hasPocLinks ? 'Public PoC mevcut (link aşağıda)'
      : (hasPocCount ? 'Public PoC mevcut (' + r.pocCount + ' depo; link alınamadı)'
      : (r.publicExploit ? 'Exploit sinyali var (PoC linki yok)' : 'Bilinen istismar yok')));
  const pocLinks = (r.pocRepos || []).map(p => '<a href="' + esc(p.url) + '" style="color:' + C.navyMed + '">' + esc(p.name) + '</a>' + (p.stars != null ? ' (' + p.stars + ' yıldız)' : '')).join('<br>');
  const pocs = (r.pocRepos || []).length
    ? (r.pocCount || 0) + ' GitHub deposu' + (r.pocTopStars ? ' (en çok ' + r.pocTopStars + ' yıldız)' : '') + ':<br>' + pocLinks
    : ((r.pocCount || 0) > 0 ? (r.pocCount + ' GitHub deposu bulundu (link sınırı)') : 'bulunamadı');

  // veri tablosu satiri yardimcisi
  const row = (label, val) =>
    '<tr><td style="padding:7px 10px;border-bottom:1px solid ' + C.border + ';color:' + C.navyMed + ';font-weight:bold;width:38%;vertical-align:top">' + label + '</td>' +
    '<td style="padding:7px 10px;border-bottom:1px solid ' + C.border + ';vertical-align:top">' + val + '</td></tr>';

  const dataTable =
    '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="border:1px solid ' + C.border + ';border-radius:6px;margin:10px 0;font-size:13px">' +
    row('Etkilenen Watchlist Ürünü', watchlist) +
    row('Sorumlu Ekip', [...new Set(mi.map(m => m.owner).filter(Boolean))].map(esc).join(', ') || '-') +
    row('Etkilenen Varlık Sayısı', String(mi.length)) +
    row('Etkilenen Varlıklar', assetsStr) +
    row('Internet Facing', ifx ? '<b style="color:' + C.orange + '">EVET</b>' : 'Hayır') +
    row('Business Criticality', esc(r.businessCriticality || '-') + (dataClass !== '-' ? ' · Veri: ' + esc(dataClass) : '')) +
    row('Etkilenen Sistem/Sürüm', cpeStr) +
    row('CPE Doğrulama', cpeOk ? '<span style="color:#27ae60">NVD CPE eşleşmesi var</span>' : '<span style="color:#999">CPE doğrulanamadı</span>') +
    row('Yayın Tarihi', pubStr || '-') +
  row('CWE', (r.cwe || []).length ? esc((r.cwe || []).join(', ')) : '-') +
    (RS.includeMitre ? row('MITRE ATT&CK', esc(a.mitre || '-')) : '') +
    row('Saldırı Vektörü', esc(a.saldiriVektoru || '-') + (r.cvssVector ? '<br><span style="color:#888;font-size:12px">' + esc(r.cvssVector) + '</span>' : '')) +
    row('CVSS', (r.cvssScore != null ? r.cvssScore : 'veri yok') + ' (' + esc(r.cvssSeverity || '-') + ')' + (r.cvssVersion ? ' · CVSS v' + esc(r.cvssVersion) : '')) +
    row('EPSS Puanı', r.epss != null ? (r.epss * 100).toFixed(2) + '%' : '-') +
    row('İstismar Durumu', esc(istismar)) +
    row('IOC / Tespit', esc(a.iocTespit || '-')) +
    row('Mitigasyon', esc(a.mitigasyon || '-')) +
    '</table>';

  return '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:#fff;border:1px solid ' + C.border + ';border-left:4px solid ' + (sev[r.priority] || C.navyMed) + ';border-radius:8px;margin:0 0 14px 0">' +
    '<tr><td style="padding:16px 20px">' +
    '<table role="presentation" width="100%"><tr>' +
      '<td style="font-size:16px;font-weight:bold;color:' + C.navy + '">' + esc(r.cveId) +
        (r.previouslyNotified ? ' <span style="background:#eef1f4;color:#777;padding:2px 8px;border-radius:20px;font-size:11px;font-weight:normal">↺ daha önce bildirildi</span>' : '') +
        (updatedOld ? ' <span style="background:#fff4e6;color:#c87f0a;padding:2px 8px;border-radius:20px;font-size:11px;font-weight:normal">güncellendi (eski CVE · ' + esc(pubStr) + ')</span>' : '') + '</td>' +
      '<td align="right"><span style="background:' + (sev[r.priority] || C.navyMed) + ';color:' + C.navy + ';padding:3px 10px;border-radius:20px;font-size:12px;font-weight:bold">' + esc(r.priority) + '</span></td>' +
    '</tr></table>' +
    '<p style="margin:8px 0;line-height:1.55"><b style="color:' + C.navyMed + '">Özet:</b> ' + esc(a.ozet) + '</p>' +
    dataTable +
    '<p style="margin:8px 0;line-height:1.55"><b style="color:' + C.navyMed + '">Sömürü (Pentest / ZY-SZ):</b> ' + esc(a.somuru) + '</p>' +
    (RS.includeDetectionQueries ? detectionBlock(r) : '') +
    refsBlock(r) +
    '<p style="margin:6px 0;font-size:12px;color:#555"><b style="color:' + C.navyMed + '">PoC / Exploit:</b> ' + pocs + '</p>' +
    '</td></tr></table>';
};

const header =
  '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="margin:0 0 26px 0"><tr>' +
  '<td><h1 style="margin:0;color:' + C.navy + ';font-size:26px">Envanterdeki Varlıklara Yönelik CVE Analizi</h1>' +
  '<p style="margin:4px 0 0 0;color:' + C.navyMed + '">Zafiyet İstihbarat Raporu · ' + new Date().toISOString().slice(0, 16).replace('T', ' ') + ' UTC</p></td>' +
  '</tr></table>';

const twoCol =
  '<table role="presentation" width="100%" cellpadding="0" cellspacing="0"><tr>' +
  '<td width="49%" valign="top">' + metricsCard + '</td><td width="2%"></td>' +
  '<td width="49%" valign="top">' + critCard + '</td></tr></table>';

const html =
  '<div style="background:' + C.bg + ';padding:28px;font-family:Segoe UI,Roboto,Arial,sans-serif;color:' + C.navy + '">' +
  '<div style="max-width:900px;margin:0 auto">' +
  header + twoCol + findingsCard +
  card('Detaylı Teknik Analiz (' + M + ' CVE) — ZY/SZ + DE/SOC',
    (reports.length ? reports.map(detailBlock).join('') : '<p>Envanterle eşleşen CVE bulunamadı.</p>')) +
  '<p style="color:#aaa;font-size:12px;text-align:center;margin-top:20px">Otomatik üretildi · Sömürü ve tespit bölümleri yalnızca toplanan veriye dayanır.</p>' +
  '</div></div>';

const titlePrefix = MODE === 'hourly' ? '🔴 Saatlik İnternet-Facing Uyarısı'
  : MODE === 'daily' ? '📊 Günlük Zafiyet Raporu'
  : MODE === 'api' ? '🔌 Zafiyet Raporu (API)'
  : '🔴 Zafiyet Raporu';
const subject = titlePrefix + ' — ' + (stats.criticalCount ?? 0) + ' kritik / ' + M + ' CVE (' + new Date().toISOString().slice(0, 10) + ')';
sd.lastReport = { reportsGenerated: M, matched: matchedN, criticalCount: stats.criticalCount ?? 0, at: new Date().toISOString() };

// ---- Diger araclar icin tam yapisal veri (cache + API) ----
const refUrls = (r) => {
  const cid = encodeURIComponent(r.cveId);
  return { nvd: 'https://nvd.nist.gov/vuln/detail/' + cid, mitre: 'https://www.cve.org/CVERecord?id=' + cid, vendor: (r.vendorRefs || []).slice(0, 5) };
};
const reportData = {
  generatedAt: new Date().toISOString(),
  mode: MODE,
  stats: stats,
  matched: matchedN,
  reportsGenerated: M,
  internetFacingCount: ifCount,
  cves: reports.map(r => ({
    cveId: r.cveId, priority: r.priority,
    cvssScore: r.cvssScore, cvssSeverity: r.cvssSeverity, cvssVector: r.cvssVector, cvssVersion: r.cvssVersion,
    epss: r.epss, knownExploited: r.knownExploited, ransomware: r.ransomware,
    publicExploit: r.publicExploit, pocCount: r.pocCount, pocRepos: r.pocRepos || [],
    cwe: r.cwe || [], published: r.published, previouslyNotified: r.previouslyNotified || false,
    matchedInventory: r.matchedInventory || [],
    internetFacing: (r.matchedInventory || []).some(m => m.internetFacing),
    references: refUrls(r),
    analysis: r.analysis || {}
  }))
};
sd.lastReportJson = reportData;

return [{ json: { subject, html, reportsGenerated: M, matched: matchedN, mode: MODE, shouldNotify, reportData } }];

// Telegram: yonetici ozeti + bulgu tablosu (deterministik, echo yok)
const reports = ($('Aggregate Analyses').first().json.reports || []).filter(r => r && !r._empty && r.cveId);
const ps = $('Priority Scoring').first().json;
const stats = ps.stats || {};
const matchedN = (ps.inventoryMatched || []).length;
const M = reports.length;
const order = { CRITICAL: 0, HIGH: 1, MEDIUM: 2, LOW: 3 };
reports.sort((a, b) => (order[a.priority] ?? 9) - (order[b.priority] ?? 9) || (b.cvssScore ?? 0) - (a.cvssScore ?? 0));

let exec = '';
try { exec = ($('Exec Summary LLM').first().json.text || '').toString().trim().replace(/[*_\u0060#]/g, ''); } catch (e) {}

let t = '🔴 **ZAFİYET İSTİHBARAT RAPORU** — ' + new Date().toISOString().slice(0, 16).replace('T', ' ') + ' UTC\n\n';
if (exec) t += exec + '\n\n';
t += '📊 ' + (stats.nvdCves ?? '?') + ' CVE tarandı · KEV ' + (stats.kevTotal ?? '?') +
     ' · ' + (stats.criticalCount ?? 0) + 'C/' + (stats.highCount ?? 0) + 'H/' + (stats.mediumCount ?? 0) + 'M' +
     ' · Eşleşme ' + matchedN + ' · Rapor ' + M + '\n\n';

if (reports.length) {
  t += '**Bulgular** (CVE · CVSS · EPSS · Ortam · Ürün · Kritiklik):\n';
  for (const r of reports.slice(0, 15)) {
    const env = (r.matchedInventory || []).some(m => m.internetFacing) ? 'İnternete Açık' : 'İç Ortam';
    const prod = [...new Set((r.matchedInventory || []).map(m => m.product))].join('/') || '-';
    const epss = r.epss != null ? (r.epss * 100).toFixed(0) + '%' : '-';
    t += '• ' + r.cveId + (r.previouslyNotified ? ' ↺' : '') + ' · ' + (r.cvssScore ?? '?') + ' · ' + epss + ' · ' + env + ' · ' + prod + ' · **' + r.priority + '**\n';
  }
  if (reports.length > 15) t += '… +' + (reports.length - 15) + ' bulgu daha (e-postada)\n';
} else {
  t += 'Envanterle eşleşen bulgu yok.\n';
}
t += '\nTüm teknik detay (saldırı vektörü, IOC/tespit, mitigasyon, PoC) e-posta raporundadır.';
return [{ json: { text: t } }];

// Telegram icin: markdown entity'lerini temizle (parse hatasi onler) + 4096 limiti icin parcala
const LIMIT = 4000;
let text = ($input.first().json.text || '').trim();

// LLM ciktisi Discord markdown — Telegram'in Markdown parser'i dengesiz entity'lerde
// "can't parse entities" hatasi verir. Linkleri duz metne cevir, kalan isaretleri kaldir.
text = text
  .replace(/\[([^\]]*)\]\(([^)]*)\)/g, '$1 ($2)')   // [metin](url) -> metin (url)
  .replace(/\u0060\u0060\u0060[a-z]*\n?/gi, '')      // kod blogu citleri (backtick x3)
  .replace(/[\u0060*_~]/g, '')                       // kalan entity karakterleri
  .replace(/^#{1,6}\s*/gm, '');                      // basliklari duzlestir

const chunks = [];
let buf = '';
for (const line of text.split('\n')) {
  if ((buf + '\n' + line).length > LIMIT) {
    if (buf) chunks.push(buf);
    buf = line.slice(0, LIMIT);
  } else {
    buf = buf ? buf + '\n' + line : line;
  }
}
if (buf) chunks.push(buf);
if (!chunks.length) chunks.push('(bos brifing)');
return chunks.map((c, i) => ({ json: { chunk: c, part: i + 1, totalParts: chunks.length } }));

// Calistirma gecmisi (son 50)
const stats = $('Priority Scoring').first().json.stats || {};
let reportsGenerated = null;
try { reportsGenerated = $('Compose Consolidated Report').first().json.reportsGenerated; } catch (e) {}
const record = { ...stats, reportsGenerated, executionId: $execution.id, workflow: 'Vuln Intel Suite', status: 'completed' };
const sd = $getWorkflowStaticData('global');
sd.runHistory = sd.runHistory || [];
sd.runHistory.push(record);
if (sd.runHistory.length > 50) sd.runHistory = sd.runHistory.slice(-50);
return [{ json: record }];

const item = $input.first().json;

let raw =
  item.cveId ?? item.cve ??
  (item.query && (item.query.cve || item.query.cveId)) ??
  (item.body && (item.body.cve || item.body.cveId)) ??
  item.chatInput ?? '';

raw = String(raw).trim().toUpperCase();
const match = raw.match(/CVE-\d{4}-\d{4,}/);
if (!match) {
  throw new Error('Gecerli bir CVE ID bulunamadi: "' + raw + '". Beklenen format: CVE-YYYY-NNNN');
}
// Flow 1 handoff'undan veya webhook query'sinden gelen envanter baglami (varsa)
const q = item.query || {};
const ifRaw = item.internetFacing ?? q.internetFacing ?? null;
const ctx = {
  internetFacing: (ifRaw === true || ifRaw === 'true') ? true : (ifRaw === false || ifRaw === 'false') ? false : null,
  products: item.products ?? q.products ?? null,
  owner: item.owner ?? q.owner ?? null,
  priority: item.priority ?? q.priority ?? null
};
return [{ json: { cveId: match[0], ...ctx } }];

// All 4 fetchers have run sequentially before this node.
const cveId = $('Input Validator').first().json.cveId;

let nvd = {};
try {
  const raw = $('Fetch CVE Data').first().json;
  const v = raw?.vulnerabilities?.[0]?.cve;
  if (v) {
    const m = v.metrics || {};
    const pick = (arr) => (arr && arr[0]) ? arr[0] : null;
    const me31 = pick(m.cvssMetricV31), me30 = pick(m.cvssMetricV30), me40 = pick(m.cvssMetricV40), me2 = pick(m.cvssMetricV2);
    let _s=null,_sev=null,_vec=null,_ver=null;
    for (const cand of [
      me31 && { d: me31.cvssData, sev: me31.cvssData?.baseSeverity, ver:'3.1' },
      me30 && { d: me30.cvssData, sev: me30.cvssData?.baseSeverity, ver:'3.0' },
      me40 && { d: me40.cvssData, sev: me40.cvssData?.baseSeverity, ver:'4.0' },
      me2  && { d: me2.cvssData,  sev: me2.baseSeverity, ver:'2.0' }
    ]) { if (cand && cand.d && cand.d.baseScore != null) { _s=cand.d.baseScore; _sev=(cand.sev||'').toUpperCase()||null; _vec=cand.d.vectorString||null; _ver=cand.ver; break; } }
    nvd = {
      description: (v.descriptions || []).find(d => d.lang === 'en')?.value || '',
      published: v.published || '',
      cvssScore: _s,
      cvssSeverity: _sev,
      cvssVector: _vec,
      cvssVersion: _ver,
      cwe: (v.weaknesses || [])
        .flatMap(w => (w.description || []).map(d => d.value))
        .filter(x => x && x !== 'NVD-CWE-noinfo'),
      vendorRefs: (v.references || []).map(rf => rf.url).filter(Boolean).slice(0, 6)
    };
  } else {
    nvd = { note: 'NVD kaydi bulunamadi veya yanit bos' };
  }
} catch (e) { nvd = { error: String(e) }; }

let kev = { listed: false };
try {
  const cat = $('Fetch CISA KEV').first().json?.vulnerabilities || [];
  const hit = cat.find(x => x.cveID === cveId);
  if (hit) {
    kev = {
      listed: true,
      vulnerabilityName: hit.vulnerabilityName,
      dateAdded: hit.dateAdded,
      dueDate: hit.dueDate,
      ransomware: hit.knownRansomwareCampaignUse,
      requiredAction: hit.requiredAction
    };
  }
} catch (e) { kev = { listed: false, error: String(e) }; }

let epss = {};
try {
  const d = $('Fetch EPSS Score').first().json?.data?.[0];
  if (d) {
    epss = { score: parseFloat(d.epss), percentile: parseFloat(d.percentile) };
  } else {
    epss = { note: 'EPSS skoru bulunamadi' };
  }
} catch (e) { epss = { error: String(e) }; }

let poc = { found: false, count: 0, repos: [] };
try {
  const gh = $('Fetch PoC Check').first().json;
  const items = gh?.items || [];
  poc = {
    found: items.length > 0,
    count: gh?.total_count ?? items.length,
    repos: items.slice(0, 5).map(r => ({
      name: r.full_name, url: r.html_url,
      stars: r.stargazers_count, description: r.description
    }))
  };
} catch (e) { poc = { found: false, error: String(e) }; }

const iv = $('Input Validator').first().json;
const inventory = {
  internetFacing: iv.internetFacing ?? null,
  products: iv.products ?? null,
  owner: iv.owner ?? null,
  priority: iv.priority ?? null
};

return [{ json: { cveId, nvd, kev, epss, poc, inventory } }];

options.systemMessage:
Sen kidemli bir zafiyet analisti, sizma testi uzmani ve detection engineer'sin. Sana TEK bir CVE'nin zenginlestirilmis verisi (NVD, CISA KEV, FIRST EPSS, GitHub PoC) JSON olarak veriliyor. SADECE su semaya uyan gecerli bir JSON dondur, baska hicbir sey yazma:
{"ozet":"1-2 cumle zafiyet tanimi","saldiriVektoru":"erisim yolu, kimlik dogrulama, kullanici etkilesimi; CVSS vektorunu sade dille acikla","somuru":"pentest bakisiyla pratik somuru, on kosullar, etki; veri sinirliysa belirt","iocTespit":"detection engineering: log kaynagi + aranacak IOC/pattern","mitigasyon":"patch + gecici workaround + telafi edici kontrol","mitre":"olasi MITRE ATT&CK teknigi adi ve ID, or. Exploit Public-Facing Application T1190","splAciklama":"SPL ne tespit eder, hangi log/alanlar","spl":"kapsamli calistirilabilir Splunk SPL, gercekci index/sourcetype/alan, stats/eval/esik","sigmaAciklama":"Sigma kuralinin amaci ve hedef log kaynagi","sigma":"tam gecerli Sigma kurali YAML: title,status,description,logsource,detection,condition,falsepositives,level"}
Turkce yaz. Yalnizca verilen veriyi kullan, uydurma. JSON disinda metin yok.

parameters.jsCode:
const d = $('Extract CVE Details').first().json;

// Agent JSON analizini ayristir
let raw = ($json.output || $json.text || '').toString().trim();
raw = raw.replace(/^[\s\S]*?\u0060\u0060\u0060(?:json)?/i, '').replace(/\u0060\u0060\u0060[\s\S]*$/i, '').trim();
let a = {};
try { a = JSON.parse(raw); } catch (e) { const m = raw.match(/\{[\s\S]*\}/); try { a = m ? JSON.parse(m[0]) : {}; } catch (_) { a = {}; } }
const looksLikeQuery = (s) => {
  if (!s) return false; s = ('' + s).trim();
  return /^(spl|sigma|yaml|json)\b/i.test(s) ||
    /\bindex\s*=|\bsourcetype\s*=|EventCode\s*=|\|\s*stats\b|\|\s*where\b|\|\s*search\b/i.test(s) ||
    /^\s*title:\s|logsource:|detection:\s|condition:\s/im.test(s);
};
let splX = a.spl || '', sigmaX = a.sigma || '';
let ozetX = a.ozet || a.summary || '';
if (looksLikeQuery(ozetX)) {
  const t = ('' + ozetX).trim();
  if (/^\s*title:|logsource:|detection:/im.test(t) || /^(yaml|sigma)\b/i.test(t)) { if (!sigmaX) sigmaX = t.replace(/^(yaml|sigma)\s*/i, ''); }
  else { if (!splX) splX = t.replace(/^splunk\s*/i, ''); }
  ozetX = '';
}
if (!ozetX) {
  const ds = ('' + ((d.nvd && d.nvd.description) || '')).split(/(?<=[.!?])\s/)[0];
  ozetX = (ds && !looksLikeQuery(ds)) ? ds.slice(0, 200) : (d.cveId + ' zafiyeti icin ozet uretilemedi.');
}
const cleanX = (v, fb) => (v && !looksLikeQuery(v)) ? v : fb;
const analysis = {
  ozet: ozetX,
  saldiriVektoru: cleanX(a.saldiriVektoru || a.attackVector, '-'),
  somuru: cleanX(a.somuru || a.exploit, 'Teknik somuru verisi sinirli.'),
  iocTespit: cleanX(a.iocTespit || a.tespit || a.detection, 'Tespit onerisi uretilemedi.'),
  mitigasyon: cleanX(a.mitigasyon || a.mitigation, '-'),
  mitre: a.mitre || '-', spl: splX, sigma: sigmaX, splAciklama: cleanX(a.splAciklama, ''), sigmaAciklama: cleanX(a.sigmaAciklama, '')
};

const C = { navy: '#001C30', navyMed: '#176B87', orange: '#FF6B00', orangeLt: '#FFD3B0', bg: '#F8F9FA', border: '#DEE2E6' };
const esc = s => String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

const nvd = d.nvd || {};
const cvss = nvd.cvssScore != null ? nvd.cvssScore : '?';
const sevName = nvd.cvssSeverity || '-';
const sevColor = { CRITICAL: '#FF6B6B', HIGH: '#FF8B94', MEDIUM: '#FFD3B0', LOW: '#A8E6CF' }[(sevName || '').toUpperCase()] || C.navyMed;
const epssTxt = (d.epss && d.epss.score != null) ? (d.epss.score * 100).toFixed(2) + '%' : '-';
const kevTxt = d.kev && d.kev.listed ? 'EVET - ' + d.kev.dateAdded + (d.kev.ransomware && d.kev.ransomware !== 'Unknown' ? ' (ransomware: ' + d.kev.ransomware + ')' : '') : 'Hayir';
const inv = d.inventory || {};
const invStr = inv.products ? esc(inv.products) + (inv.owner ? ' (' + esc(inv.owner) + ')' : '') + (inv.internetFacing ? ' <b style="color:' + C.orange + '">[internet-facing]</b>' : '') : '-';
const istismar = (d.kev && d.kev.listed)
  ? 'Aktif istismar (CISA KEV)'
  : ((d.poc && d.poc.found && (d.poc.repos || []).length) ? 'Public PoC mevcut (link aşağıda)'
    : ((d.poc && d.poc.count > 0) ? 'Public PoC mevcut (' + d.poc.count + ' depo)' : 'Bilinen istismar yok'));
const pocList = d.poc && d.poc.found
  ? (d.poc.count || 0) + ' GitHub deposu:<br>' + (d.poc.repos || []).map(r => '<a href="' + esc(r.url) + '" style="color:' + C.navyMed + '">' + esc(r.name) + '</a> (' + (r.stars || 0) + ' yıldız)').join('<br>')
  : 'bulunamadı';

const row = (label, val) =>
  '<tr><td style="padding:7px 10px;border-bottom:1px solid ' + C.border + ';color:' + C.navyMed + ';font-weight:bold;width:38%;vertical-align:top">' + label + '</td>' +
  '<td style="padding:7px 10px;border-bottom:1px solid ' + C.border + ';vertical-align:top">' + val + '</td></tr>';

const dataTable =
  '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="border:1px solid ' + C.border + ';border-radius:6px;margin:10px 0;font-size:13px">' +
  row('Etkilenen Envanter', invStr) +
  (inv.owner ? row('Sorumlu Ekip', esc(inv.owner)) : '') +
  row('Internet Facing', inv.internetFacing ? '<b style="color:' + C.orange + '">EVET</b>' : 'Hayır') +
  row('CWE', (nvd.cwe || []).length ? esc((nvd.cwe || []).join(', ')) : '-') +
  (analysis.mitre && analysis.mitre !== '-' ? row('MITRE ATT&CK', esc(analysis.mitre)) : '') +
  row('Saldırı Vektörü', esc(analysis.saldiriVektoru) + (nvd.cvssVector ? '<br><span style="color:#888;font-size:12px">' + esc(nvd.cvssVector) + '</span>' : '')) +
  row('CVSS', (nvd.cvssScore != null ? nvd.cvssScore : 'veri yok') + ' (' + esc(sevName) + ')' + (nvd.cvssVersion ? ' · CVSS v' + esc(nvd.cvssVersion) : '')) +
  row('EPSS Puanı', epssTxt) +
  row('İstismar Durumu', esc(istismar)) +
  row('IOC / Tespit', esc(analysis.iocTespit)) +
  row('Mitigasyon', esc(analysis.mitigasyon)) +
  '</table>';

const codeBox = (label, content) =>
  '<div style="margin:6px 0"><div style="font-size:12px;font-weight:bold;color:' + C.navyMed + '">' + label + '</div>' +
  '<pre style="margin:3px 0;padding:10px 12px;background:#0d1b2a;color:#e0e6ed;border-radius:6px;font-family:Consolas,Monaco,monospace;font-size:12px;white-space:pre-wrap;word-break:break-word">' + content + '</pre></div>';
const enote = (t) => t ? '<p style="margin:4px 0;font-size:12px;color:#555;line-height:1.5">' + esc(t) + '</p>' : '';
const detection = (analysis.spl || analysis.sigma)
  ? '<div style="margin:10px 0;padding:12px 14px;background:#f4f7fa;border:1px solid ' + C.border + ';border-radius:8px">' +
    '<div style="font-weight:bold;color:' + C.navy + ';margin-bottom:4px">🔎 Tespit / İnceleme</div>' +
    '<p style="margin:2px 0 8px 0;font-size:11px;color:#888">Sorgular otomatik üretildi; ortamınıza uyarlayın.</p>' +
    (analysis.spl ? enote(analysis.splAciklama) + codeBox('Splunk SPL', esc(analysis.spl)) : '') +
    (analysis.sigma ? enote(analysis.sigmaAciklama) + codeBox('Sigma', esc(analysis.sigma)) : '') + '</div>'
  : '';

const cid = encodeURIComponent(d.cveId);
const refLinks = [
  { label: 'NVD', url: 'https://nvd.nist.gov/vuln/detail/' + cid },
  { label: 'MITRE CVE.org', url: 'https://www.cve.org/CVERecord?id=' + cid }
];
for (const u of ((nvd.vendorRefs) || []).slice(0, 5)) {
  let host = u;
  try { host = new URL(u).hostname.replace(/^www\./, ''); } catch (e) {}
  refLinks.push({ label: host, url: u });
}
const refsLine = '<p style="margin:6px 0;font-size:12px;color:#555"><b style="color:' + C.navyMed + '">Referanslar:</b> ' +
  refLinks.map(l => '<a href="' + esc(l.url) + '" style="color:' + C.navyMed + '">' + esc(l.label) + '</a>').join(' · ') + '</p>';

const subject = '[CVE Brief] ' + d.cveId + (d.kev && d.kev.listed ? ' - CISA KEV' : '') + (nvd.cvssScore != null ? ' - CVSS ' + nvd.cvssScore : '');

const html =
  '<div style="background:' + C.bg + ';padding:24px;font-family:Segoe UI,Roboto,Arial,sans-serif;color:' + C.navy + '">' +
  '<div style="max-width:820px;margin:0 auto">' +
  '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:#fff;border-radius:12px;border-top:4px solid ' + C.orange + ';box-shadow:0 4px 6px rgba(0,0,0,0.05)">' +
  '<tr><td style="padding:22px 24px">' +
  '<table role="presentation" width="100%"><tr>' +
    '<td style="font-size:20px;font-weight:bold;color:' + C.navy + '">' + esc(d.cveId) + '</td>' +
    '<td align="right"><span style="background:' + sevColor + ';color:' + C.navy + ';padding:4px 12px;border-radius:20px;font-size:12px;font-weight:bold">' + esc(sevName) + '</span></td>' +
  '</tr></table>' +
  '<p style="margin:10px 0;line-height:1.55"><b style="color:' + C.navyMed + '">Özet:</b> ' + esc(analysis.ozet) + '</p>' +
  dataTable +
  '<p style="margin:8px 0;line-height:1.55"><b style="color:' + C.navyMed + '">Sömürü (Pentest / ZY-SZ):</b> ' + esc(analysis.somuru) + '</p>' +
  detection +
  refsLine +
  '<p style="margin:6px 0;font-size:12px;color:#555"><b style="color:' + C.navyMed + '">PoC / Exploit:</b> ' + pocList + '</p>' +
  '</td></tr></table>' +
  '<p style="color:#aaa;font-size:12px;text-align:center;margin-top:16px">Otomatik üretildi · Tek CVE sorgu yanıtı (Explainer).</p>' +
  '</div></div>';

const summary = analysis.ozet;
try {
  const sd = $getWorkflowStaticData('global');
  sd.lastExplainer = { cveId: d.cveId, at: new Date().toISOString(), analysis, enrichment: d,
    references: { nvd: 'https://nvd.nist.gov/vuln/detail/' + d.cveId, mitre: 'https://www.cve.org/CVERecord?id=' + d.cveId } };
} catch (e) {}
return [{ json: { subject, html, summary, analysis, ...d } }];
